const MAX_CLUES = 5;
const RECENT_QUEUE_SIZE = 100;
const MAX_TRACKED_THREADS = 500;
const activeGames = new Map();
const recentByThread = new Map();

function pickPerson(threadID) {
  const recent = recentByThread.get(threadID) || [];
  const recentSet = new Set(recent);
  const total = PEOPLE.length;
  let chosen = -1;
  for (let attempts = 0; attempts < 50; attempts++) {
    const i = Math.floor(Math.random() * total);
    if (!recentSet.has(i)) { chosen = i; break; }
  }
  if (chosen === -1) {
    for (let i = 0; i < total; i++) if (!recentSet.has(i)) { chosen = i; break; }
  }
  if (chosen === -1) chosen = Math.floor(Math.random() * total);
  const newRecent = [chosen, ...recent].slice(0, RECENT_QUEUE_SIZE);
  if (recentByThread.has(threadID)) recentByThread.delete(threadID);
  recentByThread.set(threadID, newRecent);
  while (recentByThread.size > MAX_TRACKED_THREADS) {
    const oldest = recentByThread.keys().next().value;
    recentByThread.delete(oldest);
  }
  return PEOPLE[chosen];
}

function normAnswer(str) {
  return String(str || "")
    .toLowerCase()
    .replace(/[أإآ]/g, "ا")
    .replace(/ة/g, "ه")
    .replace(/ى/g, "ي")
    .replace(/[ًٌٍَُِّْ]/g, "")
    .replace(/[^\p{L}\p{N}\s]/gu, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function checkAnswer(input, person) {
  const n = normAnswer(input);
  if (!n) return false;
  if (normAnswer(person.answer) === n) return true;
  return (person.alt || []).some(a => normAnswer(a) === n);
}

function registerReply(botMsgID, data) {
  if (!global.NeroBot?.onReply) return;
  global.NeroBot.onReply.set(botMsgID, { commandName: "مناني", ...data, messageID: botMsgID });
}

function clueStars(current, max) {
  return "⭐".repeat(max - current) + "🌑".repeat(current);
}

module.exports = {
  config: {
    name: "مناني",
    aliases: ["شخصية", "mnanani"],
    version: "2.0",
    author: "Nero",
    role: 0,
    shortDescription: "من أنا؟ — خمّن الشخصية من الإشارات",
    longDescription: "البوت يعطيك 5 إشارات تدريجية عن شخصية مشهورة — من يخمّن أولاً يربح! +500 شخصية متنوعة.",
    category: "game",
    guide: "{p}مناني — يبدأ لعبة من أنا؟\n{p}مناني وقف — يوقف اللعبة (للمدير)\n{p}مناني عدد — يبين عدد الشخصيات",
    countDown: 5,
  },

  onStart: async function ({ api, event, args }) {
    const { threadID, messageID, senderID } = event;
    if (!isPrivilegedSender(senderID) && !isGamesEnabled()) return;

    const sub = (args[0] || "").trim().toLowerCase();

    if (sub === "عدد" || sub === "count") {
      return api.sendMessage(`📊 عدد الشخصيات: ${PEOPLE.length}`, threadID, () => {}, messageID);
    }

    if (sub === "وقف" || sub === "reset" || sub === "stop") {
      if (!isPrivilegedSender(senderID)) return;
      if (activeGames.has(threadID)) {
        const g = activeGames.get(threadID);
        activeGames.delete(threadID);
        if (global.NeroBot?.onReply) global.NeroBot.onReply.delete(g.botMsgID);
        return api.sendMessage("🔄 لعبة «من أنا؟» تريّضات — أي واحد يقدر يبدأ من جديد!", threadID, () => {}, messageID);
      }
      return api.sendMessage("ما كاينة حتى لعبة دايرة باش تريّض 😅", threadID, () => {}, messageID);
    }

    if (activeGames.has(threadID)) {
      return api.sendMessage("⏳ كاينة لعبة دايرة — ردّ على رسالة اللعبة وخمّن!", threadID, () => {}, messageID);
    }

    const person = pickPerson(threadID);
    const clueIdx = 0;

    const text =
      `🕵️ من أنا؟\n` +
      `${clueStars(0, MAX_CLUES)} — إشارة 1 من ${MAX_CLUES}\n\n` +
      `${person.clues[0]}\n\n` +
      `ردّ بجوابك 👇`;

    api.sendMessage(text, threadID, (err, info) => {
      if (err || !info?.messageID) return;
      activeGames.set(threadID, { person, clueIdx, botMsgID: info.messageID, starterID: senderID });
      registerReply(info.messageID, { threadID, person, clueIdx, starterID: senderID });
    }, messageID);
  },

  onReply: async function ({ api, event, usersData }) {
    const { threadID, senderID, body, messageID } = event;
    const game = activeGames.get(threadID);
    if (!game) return;

    const { person, botMsgID } = game;
    if (global.NeroBot?.onReply) global.NeroBot.onReply.delete(botMsgID);

    if (checkAnswer(body || "", person)) {
      activeGames.delete(threadID);
      const REWARD = 70;
      let name = "صاحبنا";
      try { name = (await usersData.get(senderID, "name")) || name; } catch (e) {}
      try { await usersData.addMoney(senderID, REWARD); } catch (e) {}
      let total = REWARD;
      try { total = (await usersData.get(senderID, "money")) || REWARD; } catch (e) {}
      try { api.setMessageReaction("🎉", messageID, () => {}, true); } catch (e) {}
      return api.sendMessage(
        `🏆 مبروك ${name}!\n✅ الجواب الصحيح: ${person.answer}\n⭐ ربحتي ${REWARD} نجمة!\n💫 مجموع نجومك: ${total}`,
        threadID, () => {}, messageID
      );
    }

    const nextIdx = game.clueIdx + 1;

    if (nextIdx >= MAX_CLUES) {
      activeGames.delete(threadID);
      try { api.setMessageReaction("😵", messageID, () => {}, true); } catch (e) {}
      return api.sendMessage(
        `😵 خلصات الإشارات!\nالجواب كان: ${person.answer}\nجرب مرة أخرى مع /مناني`,
        threadID, () => {}, messageID
      );
    }

    game.clueIdx = nextIdx;
    const text =
      `❌ غلط — إشارة ${nextIdx + 1} من ${MAX_CLUES}\n` +
      `${clueStars(nextIdx, MAX_CLUES)}\n\n` +
      `${person.clues[nextIdx]}\n\n` +
      `ردّ بجوابك 👇`;

    api.sendMessage(text, threadID, (err, info) => {
      if (!err && info?.messageID) {
        game.botMsgID = info.messageID;
        registerReply(info.messageID, { threadID, person, clueIdx: nextIdx });
      }
    }, messageID);
  },
};